import React from 'react';

function Footer() {
  const currentYear = new Date().getFullYear();

  return (
    <footer className="bg-gray-800 text-white py-8 mt-12 rtl">
      <div className="container mx-auto">
        <div className="flex flex-col items-center gap-5">
          <div className="text-xl font-bold">تحلیل بورس</div>
          <div className="flex gap-5">
            <a href="/" className="text-gray-300 hover:text-white transition duration-300">خانه</a>
            <a href="/about" className="text-gray-300 hover:text-white transition duration-300">درباره ما</a>
            <a href="/contact" className="text-gray-300 hover:text-white transition duration-300">تماس با ما</a>
          </div>
          <div className="text-sm text-gray-400">
            &copy; {currentYear} تحلیل بورس - همه حقوق محفوظ است
          </div>
        </div>
      </div>
    </footer>
  );
}

export default Footer;
